void
kernel_gpu_opencl_wrapper_2(knode *knodes,
                            long knodes_elem,
                            long knodes_mem,
                            int order,
                            long maxheight,
                            int count,
                            long *currKnode,
                            long *offset,
                            long *lastKnode,
                            long *offset_2,
                            int *start,
                            int *end,
                            int *recstart,
                            int *reclength)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_total_end;
    struct timeval tv_init_end;
    struct timeval tv_mem_alloc_end;
    struct timeval tv_h2d_end;
    struct timeval tv_kernel_end;
    struct timeval tv_d2h_end;
    struct timeval tv_close_start, tv_close_end;
    float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f, kernel_time = 0.0f,
          d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;
    gettimeofday(&tv_total_start, NULL);
#endif

    (void)knodes_mem;

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = (float)elapsed_ms(&tv_total_start, &tv_init_end);

    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = (float)elapsed_ms(&tv_init_end, &tv_mem_alloc_end);

    gettimeofday(&tv_h2d_end, NULL);
    h2d_time = (float)elapsed_ms(&tv_mem_alloc_end, &tv_h2d_end);
#endif

    size_t local_work_size[1];
    local_work_size[0] = (size_t)(order < 1024 ? order : 1024);
    size_t global_work_size[1];
    global_work_size[0] = (size_t)count * local_work_size[0];

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
           (int)(global_work_size[0] / local_work_size[0]), (int)local_work_size[0]);

#ifdef TIMING
    struct timeval tv_kernel_start;
    gettimeofday(&tv_kernel_start, NULL);
#endif

    #pragma omp parallel for schedule(static)
    for (int bid = 0; bid < count; bid++) {
        for (long i = 0; i < maxheight; i++) {
            long next_offset = offset[bid];
            long next_offset_2 = offset_2[bid];
            long curr = currKnode[bid];
            long last = lastKnode[bid];

            for (int thid = 0; thid < (int)local_work_size[0]; thid++) {
                if ((knodes[curr].keys[thid] <= start[bid]) &&
                    (knodes[curr].keys[thid + 1] > start[bid])) {
                    if (knodes[curr].indices[thid] < knodes_elem) {
                        next_offset = knodes[curr].indices[thid];
                    }
                }
                if ((knodes[last].keys[thid] <= end[bid]) &&
                    (knodes[last].keys[thid + 1] > end[bid])) {
                    if (knodes[last].indices[thid] < knodes_elem) {
                        next_offset_2 = knodes[last].indices[thid];
                    }
                }
            }

            offset[bid] = next_offset;
            offset_2[bid] = next_offset_2;
            currKnode[bid] = offset[bid];
            lastKnode[bid] = offset_2[bid];
        }

        int recs = recstart[bid];
        for (int thid = 0; thid < (int)local_work_size[0]; thid++) {
            if (knodes[currKnode[bid]].keys[thid] == start[bid]) {
                recs = knodes[currKnode[bid]].indices[thid];
            }
        }
        recstart[bid] = recs;

        for (int thid = 0; thid < (int)local_work_size[0]; thid++) {
            if (knodes[lastKnode[bid]].keys[thid] == end[bid]) {
                reclength[bid] = knodes[lastKnode[bid]].indices[thid] - recstart[bid] + 1;
            }
        }
    }

#ifdef TIMING
    gettimeofday(&tv_kernel_end, NULL);
    kernel_time = (float)elapsed_ms(&tv_kernel_start, &tv_kernel_end);

    gettimeofday(&tv_d2h_end, NULL);
    d2h_time = (float)elapsed_ms(&tv_kernel_end, &tv_d2h_end);

    gettimeofday(&tv_close_start, NULL);
    gettimeofday(&tv_close_end, NULL);
    close_time = (float)elapsed_ms(&tv_close_start, &tv_close_end);

    gettimeofday(&tv_total_end, NULL);
    total_time = (float)elapsed_ms(&tv_total_start, &tv_total_end);

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}
